module RefModule(
    input           clk,
    input           rst,
    input           load,
    input   [7:0]   data_in,
    output reg [7:0] data_out
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge rst) begin
        if (rst)
            data_out <= 8'b0;
        else if (load)
            data_out <= data_in;
    end

endmodule
